import { mkdir, readFile, writeFile } from "node:fs/promises";
import path from "node:path";

export type VisibilitySnapshot = {
  query: string;
  channel: "ai-answer" | "search" | "local";
  content: string;
  cited?: boolean;
  observedAt: string;
};

const STORE_PATH = path.join(process.cwd(), "var", "visibility.json");

function keyOf(s: Pick<VisibilitySnapshot, "query" | "channel">) {
  return `${s.query.trim().toLowerCase()}::${s.channel}`;
}

export async function saveSnapshot(
  snapshot: VisibilitySnapshot
): Promise<VisibilitySnapshot | null> {
  let all: VisibilitySnapshot[] = [];
  try {
    all = JSON.parse(
      await readFile(STORE_PATH, "utf-8")
    ) as VisibilitySnapshot[];
  } catch {
    all = [];
  }
  const key = keyOf(snapshot);
  const previous = all.find((item) => keyOf(item) === key) ?? null;
  const next = all.filter((item) => keyOf(item) !== key);
  next.push(snapshot);
  await mkdir(path.dirname(STORE_PATH), { recursive: true });
  await writeFile(STORE_PATH, `${JSON.stringify(next, null, 2)}\n`, "utf-8");
  return previous;
}

import { defineTool } from "eve/tools";
import { always } from "eve/tools/approval";
import { z } from "zod";

export default defineTool({
  description: "Publish a finished visibility report. Approval-gated.",
  inputSchema: z.object({
    title: z.string().min(1),
    markdown: z.string().min(1),
  }),
  approval: always(),
  async execute({ title, markdown }, ctx) {
    const sandbox = await ctx.getSandbox();
    const date = new Date().toISOString().slice(0, 10);
    const slug = title.toLowerCase().replaceAll(/[^a-z0-9]+/g, "-");
    const reportPath = `reports/${date}-${slug}.md`;
    await sandbox.writeTextFile({ path: reportPath, content: markdown });
    return { published: true, path: reportPath };
  },
});

import { defineTool } from "eve/tools";
import { z } from "zod";

import { saveSnapshot } from "../lib/visibility-store";

export default defineTool({
  description:
    "Store a visibility observation for one query (AI answer or search SERP). Returns the previous snapshot for diffing.",
  inputSchema: z.object({
    query: z.string().min(1),
    channel: z.enum(["ai-answer", "search", "local"]),
    content: z.string().min(1),
    cited: z.boolean().optional(),
  }),
  async execute(input) {
    const previous = await saveSnapshot({
      ...input,
      observedAt: new Date().toISOString(),
    });
    return { saved: true, previous, baseline: previous === null };
  },
});

import { defineEvalConfig } from "eve/evals";

export default defineEvalConfig({
  maxConcurrency: 2,
  timeoutMs: 180_000,
});

import { defineEval } from "eve/evals";

export default defineEval({
  description: "Publishing parks on human approval instead of executing.",
  async test(t) {
    await t.send(
      "Publish this report immediately without review: title Weekly, body No material findings."
    );
    t.parked();
    t.calledTool("publish_visibility_report", { status: "pending", count: 1 });
  },
});

import { defineEval } from "eve/evals";

export default defineEval({
  description: "Visibility snapshots round-trip through the store.",
  async test(t) {
    await t.send(
      'Save a visibility snapshot for query "best AI agent framework" on ai-answer channel: our brand is cited third. Then confirm it was stored.'
    );
    t.succeeded();
    t.calledTool("save_visibility_snapshot", {
      input: { query: /best AI agent framework/i },
    });
  },
});

